sql:
SELECT hu.unit_id, hu.tenure, hu.rent
FROM housing_units hu
WHERE hu.tenure = 'Renter occupied';

SELECT report_title
FROM reports
WHERE report_id = 0 AND is_public = 1;

SELECT AVG(bathrooms) AS avg_bathrooms
FROM housing_units
WHERE tenure = 'Renter occupied' AND city = 'Springfield';

SELECT metric_name, metric_value
FROM housing_statistics
WHERE strftime('%m', date_recorded) = '05';

SELECT COUNT(*) AS Total_Incomes_Above_Average
FROM housing_units
WHERE household_income > (
    SELECT AVG(household_income) 
    FROM housing_units
);

SELECT COUNT(*) AS total_owner_occupied_units
FROM housing_units
WHERE tenure = 'Owner occupied';

SELECT COUNT(*) AS Total_Severe_Problems
FROM housing_problems
WHERE severity_level = 'Severe';

SELECT unit_id, line_type, tenure, housing_problem, household_income, address, city, state, zip_code, year_built, number_of_rooms, property_value, rent, bedrooms, bathrooms, lot_size, last_inspection_date, inspector_id, notes
FROM housing_units
WHERE tenure = 'Renter occupied';

SELECT * 
FROM housing_units 
WHERE unit_id = 100;

SELECT COUNT(unit_id) AS unit_count
FROM housing_units
WHERE strftime('%Y', last_inspection_date) = '2022';
